#include<bits/stdc++.h>
using namespace std;
int n,m,a[20][20],flag=1,sum=0,maxn=0;
int main()
{
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
    	for(int j=1;j<=m;j++)
    	{
    		cin>>a[i][j];
		}
	}
	for(int i=1;i<=n;i++)
	{
		for(int j=1;j<=m;j++)
		{
			for(int p=i;p<=n;p++)
			{
				for(int q=j;q<=m;q++)
				{
					flag=1,sum=0;
					for(int k=i;k<=p;k++)
					{
						for(int l=j;l<=q;l++)
						{
							if(a[k][l]==0)
							{
								flag=0;	
							}
							sum++;
						}
					}
					if(maxn<=sum&&flag!=0)
					{
						maxn=sum;
					}
				}
			}
		}
	}
	cout<<maxn;
    return 0;
}
